import{_ as o,o as a,c as t,a2 as i}from"./chunks/framework.Bix3-HpO.js";const h=JSON.parse('{"title":"Review Page Blocks","description":"Akurai Theme Review Page Blocks","frontmatter":{"title":"Review Page Blocks","description":"Akurai Theme Review Page Blocks","weight":60,"extra":{"order":60},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/akurai/review-page-blocks"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/akurai/review-page-blocks"}],["meta",{"property":"og:title","content":"Review Page Blocks"}],["meta",{"property":"og:description","content":"Akurai Theme Review Page Blocks"}],["meta",{"name":"twitter:title","content":"Review Page Blocks"}],["meta",{"name":"twitter:description","content":"Akurai Theme Review Page Blocks"}]]},"headers":[],"relativePath":"docs/akurai/review-page-blocks.md","filePath":"docs/akurai/review-page-blocks.md"}'),s={name:"docs/akurai/review-page-blocks.md"};function c(l,e,r,n,d,u){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="review-page-blocks" tabindex="-1">Review Page Blocks <a class="header-anchor" href="#review-page-blocks" aria-label="Permalink to &quot;Review Page Blocks&quot;">​</a></h1><p>Akurai theme comes with built-in review page blocks (and shortcodes) that you can use to easily present sportsbook information.</p><hr><h2 id="using-blocks-shortcodes" tabindex="-1">Using Blocks &amp; Shortcodes <a class="header-anchor" href="#using-blocks-shortcodes" aria-label="Permalink to &quot;Using Blocks &amp; Shortcodes&quot;">​</a></h2><p>General and some specific blocks are available on Akurai review pages. Check them out below.</p><h3 id="blocks" tabindex="-1">Blocks <a class="header-anchor" href="#blocks" aria-label="Permalink to &quot;Blocks&quot;">​</a></h3><p>There are 7 review blocks available for you to use in review pages:</p><ul><li>Info Table</li><li>Pros &amp; Cons</li><li>Ratings</li><li>Banking</li><li>Offers</li><li>Bonus List</li><li>Countries</li></ul><p><img src="https://media.dinomatic.com/images/docs/akurai/review-blocks.jpg" alt="akurai-review-blocks"></p><p>5 blocks, except Bonus List and Countries, require no configuration, all you need is to just add them to the content by clicking on the block name. The information is populated from <a href="/docs/akurai/creating-review-pages">Review Fields</a> that you need to have filled in beforehand.</p><h3 id="shortcodes" tabindex="-1">Shortcodes <a class="header-anchor" href="#shortcodes" aria-label="Permalink to &quot;Shortcodes&quot;">​</a></h3><p>The same blocks are also available via shortcodes, and you can also use them in <a href="/docs/akurai/widget-areas">Review Page Sidebars</a>. Here are the formats:</p><ul><li><code>[info]</code></li><li><code>[pros_cons]</code></li><li><code>[ratings]</code></li><li><code>[banking]</code></li><li><code>[offers]</code></li><li><code>[bonus_list]</code> - At least 2 bonuses must be specified.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[bonus_list bonus_1=&quot;1st BONUS&quot; bonus_2=&quot;2nd BONUS&quot; bonus_3=&quot;&quot; bonus_4=&quot;&quot; bonus_5=&quot;&quot;]</span></span></code></pre></div><ul><li><code>[countries]</code> - You can skip the options and display the default block.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[countries show_search=&quot;1&quot; main_text=&quot;...&quot; not_supported_text=&quot;...&quot;]</span></span></code></pre></div><h3 id="screenshots" tabindex="-1">Screenshots <a class="header-anchor" href="#screenshots" aria-label="Permalink to &quot;Screenshots&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/akurai/akurai-review-blocks-content.jpg" alt="akurai-review-blocks-content"></p>',18)])])}const k=o(s,[["render",c]]);export{h as __pageData,k as default};
